/**
 * @param {number[]} nums
 * @param {number[][]} queries
 * @return {number[]}
 */
function solve(nums, queries) {
    const N = nums.length;

    // 1. Precompute P_even: P_even[i] stores the count of even numbers in nums[0...i]
    const P_even = new Array(N);
    P_even[0] = (nums[0] % 2 === 0) ? 1 : 0;
    for (let i = 1; i < N; i++) {
        P_even[i] = P_even[i - 1] + ((nums[i] % 2 === 0) ? 1 : 0);
    }

    /**
     * Finds the largest index r_prime in the range [l, r] such that nums[r_prime] <= X.
     * Returns l - 1 if no such element exists in the range.
     * Uses binary search on the indices [l, r].
     * @param {number[]} nums 
     * @param {number} l Left boundary (inclusive)
     * @param {number} r Right boundary (inclusive)
     * @param {number} X The maximum value
     * @returns {number} The index r_prime or l - 1
     */
    const find_r_prime = (l, r, X) => {
        if (nums[l] > X) return l - 1;

        let low = l;
        let high = r;
        let result = l - 1; 

        while (low <= high) {
            const mid = Math.floor((low + high) / 2);
            if (nums[mid] <= X) {
                result = mid; // Potential candidate
                low = mid + 1; // Try to find a larger index
            } else {
                high = mid - 1; // Too large
            }
        }
        return result;
    };

    const results = [];

    for (const query of queries) {
        const [l, r, k] = query;

        /**
         * Checks if the k-th remaining element is less than or equal to 2m.
         * @param {bigint} m Half of the potential answer X = 2m.
         * @returns {boolean} True if the count of remaining elements <= 2m is >= k.
         */
        const check = (m) => {
            const X = Number(m * 2n);

            // 1. Find r'(X)
            const r_prime = find_r_prime(l, r, X);

            // 2. Calculate C(X): count of even numbers in nums[l...r_prime]
            let count_removed = 0;
            if (r_prime >= l) {
                // Count of even numbers up to r_prime minus count up to l-1
                const count_up_to_r_prime = P_even[r_prime];
                const count_up_to_l_minus_1 = (l > 0) ? P_even[l - 1] : 0;
                count_removed = count_up_to_r_prime - count_up_to_l_minus_1;
            }

            // Total count of evens <= X is m (since X=2m)
            // Remaining count = m - count_removed
            const remaining_count = m - BigInt(count_removed);

            return remaining_count >= BigInt(k);
        };

        // Binary search for the smallest m such that Check(m) is true.
        // m must be at least k (if no elements are removed).
        let low = 1n;
        // Safe upper bound for m: k_max + N_max approx 10^9 + 10^5
        let high = 2000000000n + 100005n; 
        let m_min = high;

        while (low <= high) {
            const mid = low + (high - low) / 2n;
            if (check(mid)) {
                m_min = mid;
                high = mid - 1n; // Try smaller m
            } else {
                low = mid + 1n; // Need larger m
            }
        }

        // The result is 2 * m_min
        results.push(Number(m_min * 2n));
    }

    return results;
}

