        // m must be at least k (if no elements are removed).
        let low = 1n;
        // Safe upper bound for m: k_max + N_max approx 10^9 + 10^5
        let high = 2000000000n + 100005n; 
        let m_min = high;

        while (low <= high) {
            const mid = low + (high - low) / 2n;
            if (check(mid)) {
                m_min = mid;
                high = mid - 1n; // Try smaller m
            } else {
                low = mid + 1n; // Need larger m
            }
        }

        // The result is 2 * m_min
        results.push(Number(m_min * 2n));
    }

    return results;
